// Classic TR-808 groove – samples load automatically on first play
// Swap TR808 for TR909, TR606, TR707, LM1, DMX, etc.
stack(
  s("TR808_bd ~ TR808_bd ~").gain(0.95),
  s("~ TR808_sd ~ TR808_sd").gain(0.85),
  s("TR808_hh*8").gain(0.45).pan(sine.slow(4).range(0.3, 0.7)),
  s("~ ~ ~ TR808_oh").gain(0.6),
  s("~ ~ TR808_cp ~").gain(0.5)
).cpm(120)
